INSERT INTO RISK_ASSESSMENT_FACTORS (
    FACTOR_ID, ASSESSMENT_ID, FACTOR_CODE, FACTOR_NAME, WEIGHT, FACTOR_LEVEL, DESCRIPTION, SORT_ORDER, DEL_FLAG
) VALUES (#{factorId}, #{assessmentId}, #{factorCode}, #{factorName}, #{weight}, #{factorLevel}, #{description}, #{sortOrder}, 0)

INSERT INTO RISK_ASSESSMENT_SUGGESTIONS (
    SUGGESTION_ID, ASSESSMENT_ID, CATEGORY, PRIORITY, CONTENT, SORT_ORDER, DEL_FLAG
) VALUES (#{suggestionId}, #{assessmentId}, #{category}, #{priority}, #{content}, #{sortOrder}, 0)
